using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new ShoppingCart();
    }

    // ── AddItem ──────────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_CanBeReflectedInTotal()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDifferentItems_AllContributeToTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 3, price: 5.00m);

        Assert.AreEqual(25.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_DuplicateSku_UpdatesQuantity()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-001", quantity: 2, price: 10.00m);

        // Expect the second call to add to (or replace) the existing entry.
        // Either way the total should reflect the latest cart state.
        decimal total = _cart.CalculateTotal();
        Assert.IsTrue(total == 30.00m || total == 20.00m,
            $"Expected 30.00 (additive) or 20.00 (replace), but got {total}");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_ZeroQuantity_ThrowsArgumentException()
    {
        _cart.AddItem("SKU-001", quantity: 0, price: 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativeQuantity_ThrowsArgumentException()
    {
        _cart.AddItem("SKU-001", quantity: -1, price: 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NegativePrice_ThrowsArgumentException()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: -5.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NullSku_ThrowsArgumentException()
    {
        _cart.AddItem(null!, quantity: 1, price: 10.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_EmptySku_ThrowsArgumentException()
    {
        _cart.AddItem("", quantity: 1, price: 10.00m);
    }

    // ── RemoveItem ───────────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 1, price: 20.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_CartBecomesEmpty()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 15.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);

        _cart.RemoveItem("SKU-999");
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void RemoveItem_EmptyCart_ThrowsInvalidOperationException()
    {
        _cart.RemoveItem("SKU-001");
    }

    // ── CalculateTotal ───────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 2, price: 5.00m);
        _cart.RemoveItem("SKU-002");

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_LargeQuantity_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1000, price: 0.01m);

        Assert.AreEqual(10.00m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m,
            "Total should be reduced after applying a valid coupon.");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_NullCode_ThrowsArgumentException()
    {
        _cart.ApplyCoupon(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_EmptyCode_ThrowsArgumentException()
    {
        _cart.ApplyCoupon("");
    }

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void ApplyCoupon_InvalidCode_ThrowsInvalidOperationException()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 50.00m);

        _cart.ApplyCoupon("BOGUS");
    }

    [TestMethod]
    public void ApplyCoupon_OnEmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    // ── Integration / end-to-end scenarios ───────────────────────

    [TestMethod]
    public void FullWorkflow_AddItemsApplyCouponRemoveItem()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 25.00m);
        _cart.AddItem("SKU-002", quantity: 1, price: 50.00m);

        decimal beforeCoupon = _cart.CalculateTotal();
        Assert.AreEqual(100.00m, beforeCoupon);

        _cart.ApplyCoupon("SAVE10");
        decimal afterCoupon = _cart.CalculateTotal();
        Assert.IsTrue(afterCoupon < beforeCoupon,
            "Coupon should reduce the total.");

        _cart.RemoveItem("SKU-002");
        decimal afterRemove = _cart.CalculateTotal();
        Assert.IsTrue(afterRemove < afterCoupon,
            "Removing an item should further reduce the total.");
    }
}

